function animateCountUp(el,target){if(!el)return;const current=parseInt(el.textContent,10)||0;if(current===target){el.textContent=String(target);return;}const diff=target-current;const duration=320;const start=performance.now();const step=now=>{const elapsed=Math.min(now-start,duration);const progress=elapsed/duration;const eased=1-Math.pow(1-progress,3);el.textContent=String(Math.round(current+diff*eased));if(elapsed<duration)requestAnimationFrame(step);else el.textContent=String(target);};requestAnimationFrame(step);}

