function editFromModal(){if(!currentModalPrinter)return;const p=currentModalPrinter;const title=document.getElementById('modalTitle');const subtitle=document.getElementById('modalSubtitle');const infoGrid=document.getElementById('modalInfoGrid');const errorEl=document.getElementById('modalErrorContent');const tonerEl=document.getElementById('modalTonerContent');const actions=document.querySelector('#printerModal .modal-actions');if(title)title.textContent='Editar impresora';if(subtitle)subtitle.textContent=`${p.shared_name||p.name||'Impresora'} | IP: ${p.ip||'-'}`;if(errorEl)errorEl.parentElement.style.display='none';if(tonerEl)tonerEl.parentElement.style.display='none';if(infoGrid){const esc=v=>(v||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;');infoGrid.className='form-grid';infoGrid.innerHTML=`<div><label>Shared Name</label><input id="modalEditSharedName" value="${esc(p.shared_name)}"></div><div><label>Nombre</label><input id="modalEditName" value="${esc(p.name)}"></div><div><label>Modelo</label><input id="modalEditModel" value="${esc(p.model)}"></div><div><label>IP</label><input id="modalEditIp" value="${esc(p.ip)}"></div><div><label>Serie</label><input id="modalEditSerial" value="${esc(p.serial)}"></div><div><label>Ubicaci�n</label><input id="modalEditLocation" value="${esc(p.location)}"></div><div><label>Tipo</label><select id="modalEditIsColor"><option value="true"${p.is_color?' selected':''}>Color</option><option value="false"${!p.is_color?' selected':''}>Blanco y negro</option></select></div><div><label>SNMP Community</label><input id="modalEditCommunity" value="${esc(p.snmp_community||'public')}"></div>`;}if(actions)actions.innerHTML='<button class="action-button action-button-secondary" onclick="cancelEditFromModal()">Cancelar</button><button class="action-button" onclick="saveFromModal()">Guardar</button>';}
