async function saveFromModal(){if(!currentModalPrinter)return;const ip=(document.getElementById('modalEditIp')?.value||'').trim();const model=(document.getElementById('modalEditModel')?.value||'').trim();if(!model||!ip){showToast('Modelo e IP son obligatorios.','error');return;}if(!isValidIpv4(ip)){showToast('IP inv�lida.','error');return;}const modalBox=document.querySelector('#printerModal .modal-box');const savingOv=document.createElement('div');savingOv.className='modal-saving-overlay';savingOv.innerHTML='<div class="loading-spinner"></div><div class="loading-spinner-text">Guardando...</div>';if(modalBox)modalBox.appendChild(savingOv);const payload={shared_name:normalizeAddressBookPromptValue(document.getElementById('modalEditSharedName')?.value),name:normalizeAddressBookPromptValue(document.getElementById('modalEditName')?.value),model,ip,serial:normalizeAddressBookPromptValue(document.getElementById('modalEditSerial')?.value),location:normalizeAddressBookPromptValue(document.getElementById('modalEditLocation')?.value),is_color:document.getElementById('modalEditIsColor')?.value==='true',snmp_community:normalizeAddressBookPromptValue(document.getElementById('modalEditCommunity')?.value)||'public'};try{const response=await fetch(`/printers/${currentModalPrinter.id}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const data=await response.json();if(!response.ok)throw new Error(data.detail||'No se pudo guardar');showToast('Impresora actualizada','success');closePrinterModal();loadPrinters();loadSavedPrinters();}catch(error){showToast(error.message||'Error guardando impresora.','error');console.error(error);}finally{if(savingOv.parentNode)savingOv.remove();}
}
