function isValidIpv4(ip){return /^(25[0-5]|2[0-4]\d|1\d\d|[1-9]?\d)(\.(25[0-5]|2[0-4]\d|1\d\d|[1-9]?\d)){3}$/.test((ip||'').trim());}
function setFieldValidation(inputId,helpId,message='',state=''){const input=document.getElementById(inputId);const help=document.getElementById(helpId);if(!input)return;input.classList.remove('input-valid','input-invalid');if(state==='valid')input.classList.add('input-valid');if(state==='invalid')input.classList.add('input-invalid');if(help){help.textContent=message;help.className=`field-help${state==='invalid'?' error':state==='valid'?' success':''}`;}}
