function validateDiscoverFields(){const mode=document.getElementById('discoverMode')?.value||'range';const startIp=document.getElementById('discoverStartIp')?.value.trim()||'';const endIp=document.getElementById('discoverEndIp')?.value.trim()||'';const singleIp=document.getElementById('discoverSingleIp')?.value.trim()||'';let valid=true;if(mode==='range'){if(!startIp||!isValidIpv4(startIp)){setFieldValidation('discoverStartIp','discoverStartIpHelp','IP inicial inv�lida','invalid');valid=false;}else setFieldValidation('discoverStartIp','discoverStartIpHelp','OK','valid');if(!endIp||!isValidIpv4(endIp)){setFieldValidation('discoverEndIp','discoverEndIpHelp','IP final inv�lida','invalid');valid=false;}else setFieldValidation('discoverEndIp','discoverEndIpHelp','OK','valid');}else{setFieldValidation('discoverStartIp','discoverStartIpHelp','');setFieldValidation('discoverEndIp','discoverEndIpHelp','');if(!singleIp||!isValidIpv4(singleIp)){setFieldValidation('discoverSingleIp','discoverSingleIpHelp','IP inv�lida','invalid');valid=false;}else setFieldValidation('discoverSingleIp','discoverSingleIpHelp','OK','valid');}return valid;}
async function autofillPrinterNameFromIp(){const ipEl=document.getElementById('printerIp');const nameEl=document.getElementById('printerName');const communityEl=document.getElementById('printerCommunity');if(!ipEl||!nameEl)return;const ip=ipEl.value.trim();const community=(communityEl?.value||'public').trim()||'public';if(!isValidIpv4(ip))return;if(hostnameLookupController){try{hostnameLookupController.abort();}catch(e){}}hostnameLookupController=new AbortController();try{const response=await fetch(`/printers/resolve-hostname?ip=${encodeURIComponent(ip)}&community=${encodeURIComponent(community)}`,{signal:hostnameLookupController.signal});const data=await response.json();if(data?.hostname&&!nameEl.value.trim()){nameEl.value=data.hostname;nameEl.dataset.autoFilled='true';}}catch(error){if(error.name!=='AbortError')console.warn('No se pudo resolver el hostname.',error);}finally{hostnameLookupController=null;}}
function safeValue(value){if(value===null||value===undefined||value==='')return null;const n=Number(value);return Number.isNaN(n)?null:n;}
function tonerAlertText(value){if(value===null)return '';if(value<10)return '<div class="critical-text">Cr�tico: t�ner muy bajo</div>';if(value<30)return '<div class="warning-text">Advertencia: t�ner bajo</div>';return '';}
function renderTonerBar(label,value,cssClass){const numeric=safeValue(value);const display=numeric===null?'-':`${numeric}%`;const width=numeric===null?0:Math.max(0,Math.min(100,numeric));return `<div class="toner-item"><div class="toner-label-row"><span>${label}</span><span>${display}</span></div><div class="bar"><div class="bar-fill ${cssClass}" style="width:${width}%"></div></div>${label==='Black'?tonerAlertText(numeric):''}</div>`;}
function renderTonerMini(label,value,cssClass){const numeric=safeValue(value);if(numeric===null)return `<span class="tc-muted">-</span>`;const width=Math.max(0,Math.min(100,numeric));return `<div class="toner-mini" title="${label}: ${numeric}%"><div class="mini-bar"><div class="fill ${cssClass}" style="width:${width}%"></div></div><span class="mini-label">${numeric}%</span></div>`;}
function normalizeErrorType(errorText){const text=(errorText||'Sin error').toLowerCase();if(!text||text==='sin error')return 'ok';if(text.includes('cr�tico')||text.includes('critical'))return 'critical';if(text.includes('low toner')||text.includes('t�ner bajo'))return 'low';return 'other';}
function getErrorClass(errorText,status){if((status||'').toLowerCase()!=='online')return 'error-critical';const type=normalizeErrorType(errorText);if(type==='critical')return 'error-critical';if(type==='low')return 'error-warn';if(type==='other')return 'error-critical';return 'error-ok';}
function buildCard(printer){const status=(printer.status||'offline').toLowerCase();const statusClass=status==='online'?'status-online':'status-offline';const shared=printer.shared_name||'Sin shared name';const nameLine=printer.name?`<div class="printer-secondary">${printer.name}</div>`:'';let tonerHtml=renderTonerBar('Black',printer.toner_black,'bar-black');if(printer.is_color){tonerHtml+=renderTonerBar('Cyan',printer.toner_cyan,'bar-cyan');tonerHtml+=renderTonerBar('Magenta',printer.toner_magenta,'bar-magenta');tonerHtml+=renderTonerBar('Yellow',printer.toner_yellow,'bar-yellow');}return `<div class="card"><div class="card-header"><div><div class="printer-name">${shared}</div>${nameLine}<div class="printer-model">${printer.model??'-'}</div></div><div class="status-pill ${statusClass}">${status==='online'?'ONLINE':'OFFLINE'}</div></div><div class="info-row"><strong>Serie:</strong> ${printer.serial??'-'}</div><div class="info-row"><strong>IP:</strong> ${printer.ip??'-'}</div><div class="info-row"><strong>Ubicaci�n:</strong> ${printer.location??'-'}</div><div class="info-row"><strong>Error:</strong> <span class="${getErrorClass(printer.error_message,printer.status)}">${printer.error_message??'Sin error'}</span></div><div class="info-row"><strong>Tipo:</strong> ${printer.is_color?'Color':'Blanco y negro'}</div><div class="toner-section"><div class="toner-title">Consumibles</div>${tonerHtml}</div></div>`;}
function buildDashboardTableRow(printer,index){const status=(printer.status||'offline').toLowerCase();const statusHtml=status==='online'?'<span class="status-badge status-badge-online">Online</span>':'<span class="status-badge status-badge-offline">Offline</span>';const errorClass=getErrorClass(printer.error_message,printer.status);const errorText=printer.error_message||'Sin error';const normalized=normalizeErrorType(printer.error_message);let rowClass='';if(status!=='online')rowClass='row-error';else if(normalized==='critical')rowClass='row-error';else if(normalized==='low')rowClass='row-low';const tonerPieces=[renderTonerMini('K',printer.toner_black,'bar-black')];if(printer.is_color){tonerPieces.push(renderTonerMini('C',printer.toner_cyan,'bar-cyan'));tonerPieces.push(renderTonerMini('M',printer.toner_magenta,'bar-magenta'));tonerPieces.push(renderTonerMini('Y',printer.toner_yellow,'bar-yellow'));}var stagger=' stagger-row';var staggerDelay=' style="animation-delay:'+String(index*25)+'ms"';const hl=s=>_dashSearchTerm?highlightText(s,_dashSearchTerm):s;return '<tr class="'+rowClass+stagger+'"'+staggerDelay+'><td><span class="clickable-name" onclick="openPrinterDetailsFromDashboard('+index+')">'+(printer.shared_name!=null?hl(printer.shared_name):'-')+'</span></td><td>'+(printer.name!=null?hl(printer.name):'-')+'</td><td>'+(printer.model!=null?hl(printer.model):'-')+'</td><td>'+(printer.serial!=null?hl(printer.serial):'-')+'</td><td>'+(printer.ip!=null?hl(printer.ip):'-')+'</td><td>'+(printer.location!=null?hl(printer.location):'-')+'</td><td>'+statusHtml+'</td><td class="'+errorClass+'">'+hl(errorText)+'</td><td><div class="toner-inline">'+tonerPieces.join('')+'</div></td></tr>';}
function compareDashboardValues(a,b,column){const av=((a[column]??'')+'').toLowerCase().trim();const bv=((b[column]??'')+'').toLowerCase().trim();if(column==='ip'){const aip=av.split('.').map(x=>parseInt(x||'0',10));const bip=bv.split('.').map(x=>parseInt(x||'0',10));for(let i=0;i<4;i++){if((aip[i]||0)<(bip[i]||0))return -1;if((aip[i]||0)>(bip[i]||0))return 1;}return 0;}return av.localeCompare(bv);}
function sortDashboardTableColumns(data){const sorted=[...data];sorted.sort((a,b)=>{let result=compareDashboardValues(a,b,dashboardSortColumn);if(dashboardSortDirection==='desc')result*=-1;return result;});return sorted;}
function toggleTableSort(column){if(dashboardSortColumn===column){dashboardSortDirection=dashboardSortDirection==='asc'?'desc':'asc';}else{dashboardSortColumn=column;dashboardSortDirection='asc';}saveDashboardFilters();loadPrinters();}
function getDashboardRelevance(printer){const status=(printer.status||'offline').toLowerCase();const errorText=(printer.error_message||'Sin error').toLowerCase();const black=safeValue(printer.toner_black);let score=0;if(status!=='online')score+=100;if(errorText.includes('cr�tico')||errorText.includes('critical'))score+=80;else if(errorText.includes('low toner')||errorText.includes('t�ner bajo'))score+=40;else if(errorText!=='sin error')score+=20;if(black!==null)score+=Math.max(0,100-black);return score;}
function ipToNumber(ip){return String(ip||'').split('.').reduce((acc,part)=>(acc*256)+(parseInt(part,10)||0),0);}
function sortDashboardData(data,sortValue){const sorted=[...data];sorted.sort((a,b)=>{const sharedA=(a.shared_name||'').toLowerCase();const sharedB=(b.shared_name||'').toLowerCase();const nameA=(a.name||'').toLowerCase();const nameB=(b.name||'').toLowerCase();const modelA=(a.model||'').toLowerCase();const modelB=(b.model||'').toLowerCase();if(sortValue==='relevance_desc')return getDashboardRelevance(b)-getDashboardRelevance(a);if(sortValue==='relevance_asc')return getDashboardRelevance(a)-getDashboardRelevance(b);if(sortValue==='shared_name_asc')return sharedA.localeCompare(sharedB);if(sortValue==='shared_name_desc')return sharedB.localeCompare(sharedA);if(sortValue==='name_asc')return nameA.localeCompare(nameB);if(sortValue==='name_desc')return nameB.localeCompare(nameA);if(sortValue==='model_asc')return modelA.localeCompare(modelB);if(sortValue==='model_desc')return modelB.localeCompare(modelA);if(sortValue==='ip_asc')return ipToNumber(a.ip)-ipToNumber(b.ip);if(sortValue==='ip_desc')return ipToNumber(b.ip)-ipToNumber(a.ip);return 0;});return sorted;}
async function loadPrinters(){try{if(printersFetchController){try{printersFetchController.abort();}catch(e){}}printersFetchController=new AbortController();const response=await fetch('/printers/status',{signal:printersFetchController.signal});let data=await response.json();if(!Array.isArray(data))data=[];const search=(document.getElementById('searchInput')?.value||'').toLowerCase().trim();_dashSearchTerm=search;const statusFilter=document.getElementById('statusFilter')?.value||'all';const typeFilter=document.getElementById('typeFilter')?.value||'all';const errorFilter=document.getElementById('errorFilter')?.value||'all';const sortFilter=document.getElementById('sortFilter')?.value||'relevance_desc';const viewMode=document.getElementById('viewMode')?.value||'table';if(search){data=data.filter(p=>((p.shared_name||'')+' '+(p.name||'')+' '+(p.ip||'')+' '+(p.model||'')+' '+(p.serial||'')).toLowerCase().includes(search));}data=data.filter(p=>{const statusRaw=(p.status??'').toString().trim().toLowerCase();const status=statusRaw==='online'?'online':'offline';const errorType=normalizeErrorType(p.error_message);const matchesStatus=statusFilter==='all'||(statusFilter==='online'&&status==='online')||(statusFilter==='offline'&&status==='offline');const matchesType=typeFilter==='all'||(typeFilter==='color'&&!!p.is_color)||(typeFilter==='mono'&&!p.is_color);const matchesError=errorFilter==='all'||(errorFilter==='ok'&&errorType==='ok')||(errorFilter==='low'&&errorType==='low')||(errorFilter==='critical'&&errorType==='critical')||(errorFilter==='other'&&errorType==='other');return matchesStatus&&matchesType&&matchesError;});data=sortDashboardData(data,sortFilter);data=sortDashboardTableColumns(data);dashboardRawData=[...data];const cardsView=document.getElementById('dashboardCardsView');const tableView=document.getElementById('dashboardTableView');const grid=document.getElementById('printersGrid');const tableBody=document.getElementById('dashboardTableBody');grid.innerHTML='';tableBody.innerHTML='';if(!data.length){grid.innerHTML='<div class="empty-state">No hay impresoras para mostrar con esos filtros.</div>';tableBody.innerHTML='<tr><td colspan="9">No hay impresoras para mostrar.</td></tr>';document.getElementById('totalPrinters').textContent='0';document.getElementById('onlinePrinters').textContent='0';document.getElementById('offlinePrinters').textContent='0';document.getElementById('lowTonerPrinters').textContent='0';document.getElementById('lastUpdate').textContent='Sin datos';}else{let onlineCount=0,offlineCount=0,lowTonerCount=0;data.forEach((printer,index)=>{const status=(printer.status||'offline').toLowerCase();if(status==='online')onlineCount++;else offlineCount++;const black=safeValue(printer.toner_black);if(black!==null&&black<30)lowTonerCount++;if(viewMode==='cards'){const t=document.createElement('template');t.innerHTML=buildCard(printer).trim();if(t.content.firstElementChild)grid.appendChild(t.content.firstElementChild);}else{tableBody.insertAdjacentHTML('beforeend',buildDashboardTableRow(printer,index));}});animateCountUp(document.getElementById('totalPrinters'),data.length);animateCountUp(document.getElementById('onlinePrinters'),onlineCount);animateCountUp(document.getElementById('offlinePrinters'),offlineCount);animateCountUp(document.getElementById('lowTonerPrinters'),lowTonerCount);document.getElementById('lastUpdate').textContent='Actualizado: '+new Date().toLocaleTimeString();const badgeOff=document.getElementById('badge_offline');if(badgeOff){badgeOff.textContent=offlineCount;badgeOff.style.display=offlineCount>0?'flex':'none';}const badgeToner=document.getElementById('badge_toner');if(badgeToner){badgeToner.textContent=lowTonerCount;badgeToner.style.display=lowTonerCount>0?'flex':'none';}}cardsView.style.display=viewMode==='cards'?'block':'none';tableView.style.display=viewMode==='table'?'block':'none';updateDashboardSortIndicators();}catch(error){if(error.name!=='AbortError')console.error('loadPrinters error:',error);}finally{printersFetchController=null;}}
function startPrintersPolling(){stopPrintersPolling();loadPrinters();printersPollInterval=setInterval(()=>{const dash=document.getElementById('dashboard');if(dash&&dash.classList.contains('active'))loadPrinters();},PRINTERS_POLL_MS);}
