function openAddressBook(printer){currentAddressBookPrinter=printer||null;const title=document.getElementById('addressBookPrinterTitle');const meta=document.getElementById('addressBookPrinterMeta');const status=document.getElementById('addressBookStatus');const displayName=printer?.shared_name||printer?.name||printer?.model||'Impresora';if(title)title.textContent=`Libreta de direcciones - ${displayName}`;if(meta)meta.textContent=`IP: ${printer?.ip??'-'} | Modelo: ${printer?.model??'-'} | Serie: ${printer?.serial??'-'}`;if(status)status.textContent='Cargando libreta de direcciones local segura...';showTab('addressBook');loadAddressBookEntries();}
