async function openCounterHistoryModal(printerId,printerName){const modal=document.getElementById('counterHistoryModal');const title=document.getElementById('counterHistoryTitle');const subtitle=document.getElementById('counterHistorySubtitle');const list=document.getElementById('counterHistoryList');if(title)title.textContent='Historial - '+printerName;if(subtitle)subtitle.textContent='';showLoadingIn('counterHistoryList',9,'Cargando historial...');if(modal)modal.classList.add('open');try{const response=await fetch(`/printers/${printerId}/counters/history`);const data=await response.json();const items=Array.isArray(data.items)?data.items:(Array.isArray(data)?data:[]);if(!items.length){if(list)list.innerHTML='<tr><td colspan="9">No hay historial disponible.</td></tr>';return;}const fmt=v=>{if(v===null||v===undefined||v===''||v==='-')return '-';const n=Number(v);return Number.isNaN(n)?v:n.toLocaleString('es-CR');};list.innerHTML='';items.forEach(h=>{const date=h.captured_at?new Date(h.captured_at).toLocaleDateString('es-CR'):(h.date||'-');list.innerHTML+=`<tr><td>${date}</td><td>${h.period_bucket||'-'}</td><td>${fmt(h.total_pages)}</td><td>${fmt(h.copy_bw)}</td><td>${fmt(h.copy_color)}</td><td>${fmt(h.print_bw)}</td><td>${fmt(h.print_color)}</td><td>${fmt(h.bw_pages)}</td><td>${fmt(h.color_pages)}</td></tr>`;});if(subtitle)subtitle.textContent=items.length+' registro(s)';}catch(error){if(list)list.innerHTML='<tr><td colspan="9">Error cargando historial.</td></tr>';console.error('openCounterHistoryModal error:',error);}}
