function setTableFullHeight() {
    const header = document.querySelector('header');
    const filters = document.getElementById('dashboardFilters');
    const tableWrap = document.querySelector('#dashboardTableView .table-wrapper.dashboard-table-wrap');
    if (!tableWrap) return;
    const headerH = header ? header.getBoundingClientRect().height : 60;
    const filtersH = (filters && !filters.classList.contains('closed')) ? filters.getBoundingClientRect().height : 0;
    const extraTop = 20;
    const available = Math.max(320, window.innerHeight - headerH - filtersH - extraTop);
    tableWrap.style.height = available + 'px';
    tableWrap.style.maxHeight = available + 'px';
}
